class NavivoxInitialConnectIntentPayloadCache {
  Object? _payload;
  bool _hasPayload = false;

  bool get hasPayload => _hasPayload;

  void remember(Object? payload) {
    _payload = payload;
    _hasPayload = true;
  }

  Object? take() {
    final payload = _payload;
    _payload = null;
    _hasPayload = false;
    return payload;
  }
}

import '../models/connection_import.dart';
import '../shared/connection_import_parser.dart';

/// Parses the platform-channel shape used by Android connect intents.
///
/// Native code may deliver either a plain payload string or a map containing
/// the payload plus handoff provenance metadata.
SetupQrImageImport? parseNavivoxConnectIntentPayload(Object? payload) {
  final normalized = _NavivoxPlatformConnectIntentPayload.from(payload);
  if (normalized == null) return null;

  final parsed = parseNavivoxConnectionImportPayload(normalized.text);
  if (parsed == null) return null;
  return parsed.withSource(normalized.source);
}

class _NavivoxPlatformConnectIntentPayload {
  const _NavivoxPlatformConnectIntentPayload({
    required this.text,
    required this.source,
  });

  final String text;
  final PairingHandoffSource source;

  static _NavivoxPlatformConnectIntentPayload? from(Object? payload) {
    if (payload is String) return _fromString(payload);
    if (payload is Map) return _fromMap(payload);
    return null;
  }

  static _NavivoxPlatformConnectIntentPayload? _fromString(String payload) {
    final text = payload.trim();
    if (text.isEmpty) return null;
    return _NavivoxPlatformConnectIntentPayload(
      text: text,
      source: PairingHandoffSource.manual,
    );
  }

  static _NavivoxPlatformConnectIntentPayload? _fromMap(Map payload) {
    final rawText = payload['payload'];
    if (rawText is! String) return null;
    final text = rawText.trim();
    if (text.isEmpty) return null;
    return _NavivoxPlatformConnectIntentPayload(
      text: text,
      source: pairingHandoffSourceFromPlatformPayload(payload['source']),
    );
  }
}

PairingHandoffSource pairingHandoffSourceFromPlatformPayload(Object? value) {
  return switch (value?.toString().trim()) {
    'direct_app_open' => PairingHandoffSource.directAppOpen,
    'shared_text' => PairingHandoffSource.sharedText,
    _ => PairingHandoffSource.manual,
  };
}

import 'dart:async';

import 'package:flutter/services.dart';

import '../models/connection_import.dart';
import 'navivox_connect_intent_initial_payload.dart';
import 'navivox_connect_intent_payload.dart';

class NavivoxConnectIntentSource {
  NavivoxConnectIntentSource({
    MethodChannel methodChannel = const MethodChannel(_methodChannelName),
    EventChannel eventChannel = const EventChannel(_eventChannelName),
    NavivoxConnectIntentObserver? observer,
    NavivoxInitialConnectIntentPayloadCache? initialPayloadCache,
  }) : _methodChannel = methodChannel,
       _eventChannel = eventChannel,
       _observer = observer,
       _initialPayloadCache =
           initialPayloadCache ?? NavivoxInitialConnectIntentPayloadCache();

  static const _methodChannelName =
      'com.trebuchetdynamics.navivox/connect_intents';
  static const _eventChannelName =
      'com.trebuchetdynamics.navivox/connect_intents/events';

  final MethodChannel _methodChannel;
  final EventChannel _eventChannel;
  final NavivoxConnectIntentObserver? _observer;
  final NavivoxInitialConnectIntentPayloadCache _initialPayloadCache;

  Future<bool> isAvailable() async {
    try {
      final payload = await _methodChannel.invokeMethod<Object?>(
        'initialConnectIntent',
      );
      _initialPayloadCache.remember(payload);
      return true;
    } on MissingPluginException {
      return false;
    } on PlatformException {
      return false;
    }
  }

  Future<SetupQrImageImport?> initialImport() async {
    final payload = await _initialPayload();
    if (payload == null) return null;
    final result = parseNavivoxConnectIntentPayload(payload);
    if (result != null) _observer?.record(result);
    return result;
  }

  Stream<SetupQrImageImport> get imports {
    return _eventChannel
        .receiveBroadcastStream()
        .handleError((_) {})
        .map(parseNavivoxConnectIntentPayload)
        .where((result) => result != null && result.hasValues)
        .cast<SetupQrImageImport>()
        .map((result) {
          _observer?.record(result);
          return result;
        });
  }

  Future<Object?> _initialPayload() async {
    if (_initialPayloadCache.hasPayload) {
      return _initialPayloadCache.take();
    }
    try {
      return await _methodChannel.invokeMethod<Object?>('initialConnectIntent');
    } on MissingPluginException {
      return null;
    } on PlatformException {
      return null;
    }
  }
}

class NavivoxConnectIntentObserver {
  SetupQrImageImport? lastImport;

  void record(SetupQrImageImport import) {
    lastImport = import;
  }
}

import 'package:flutter_riverpod/flutter_riverpod.dart';

